/**
 * Sends a message to the Gemini API using the Chat interface to maintain context.
 */
export const sendMessageToGemini = async (message: string, history: { role: 'user' | 'model', text: string }[]) => {
  // Always initialize GoogleGenAI with the direct process.env.API_KEY as per the guidelines.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      // Properly map history to the format expected by the Gemini API.
      history: history.map(msg => ({
        role: msg.role,
        parts: [{ text: msg.text }]
      })),
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });

    // Use chat.sendMessage to continue the conversation thread.
    const response = await chat.sendMessage({ message: message });
    // Access the text property directly on the response object.
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Désolé, j'ai rencontré une erreur lors du traitement de votre demande. Veuillez réessayer plus tard.";
  }
};

