/**
 * Service pour interagir avec une instance Node-RED.
 * Par défaut, il tente de contacter l'hôte local, mais peut être configuré.
 */
export const sendToNodeRed = async (endpoint: string, data: any) => {
  const NODE_RED_URL = window.location.origin; // On assume que l'UI est servie ou accessible via le même domaine

  try {
    const response = await fetch(`${NODE_RED_URL}${endpoint}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        ...data,
        source: 'GABdev_UI',
        timestamp: new Date().toISOString()
      }),
    });

    return response.ok;
  } catch (error) {
    console.warn("Node-RED non détecté ou endpoint indisponible:", error);
    return false;
  }
};

