            </div>
          </div>

          <div className="bg-zinc-900/20 border border-white/5 rounded-[40px] overflow-hidden backdrop-blur-md">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="border-b border-white/5 bg-white/5">
                    <th className="px-8 py-6 text-[10px] font-black text-zinc-500 uppercase tracking-widest">ID</th>
                    <th className="px-8 py-6 text-[10px] font-black text-zinc-500 uppercase tracking-widest">HACKER NAME</th>
                    <th className="px-8 py-6 text-[10px] font-black text-zinc-500 uppercase tracking-widest">EMAIL ADDRESS</th>
                    <th className="px-8 py-6 text-[10px] font-black text-zinc-500 uppercase tracking-widest">TIMESTAMP</th>
