                <tbody className="divide-y divide-white/5">
                  {members.length > 0 ? members.map((member) => (
                    <tr key={member.id} className="hover:bg-white/5 transition-colors group">
                      <td className="px-8 py-6 font-mono text-xs text-zinc-600">#{member.id}</td>
                      <td className="px-8 py-6 font-black text-zinc-300 group-hover:text-[#22c55e] transition-colors">{member.hacker_name}</td>
